def gen(rng, size):
    n = max(1, min(size, 300))
    arr = [rng.randint(-5, 5)]
    for _ in range(n - 1):
        arr.append(rng.randint(-5, 5) if rng.random() < 0.75 else None)
    while arr and arr[-1] is None:
        arr.pop()
