class Solution:
    def findFrequentTreeSum(self, root):
        from collections import Counter
        cnt = Counter()
        def total(node):
            if node is None:
                return 0
            s = node.val + total(node.left) + total(node.right)
            cnt[s] += 1
            return s
        total(root)
        if not cnt:
            return []
        best = max(cnt.values())
        return [s for s, c in cnt.items() if c == best]

