class Solution:
    def findFrequentTreeSum(self, root):
        freq = {}
        def walk(node):
            if node is None:
                return 0
            s = node.val + walk(node.left) + walk(node.right)
            freq[s] = freq.get(s, 0) + 1
            return s
        walk(root)
        if not freq:
            return []
        hi = max(freq.values())
        return [s for s, c in freq.items() if c == hi]

