var findFrequentTreeSum = function(root) {
    const freq = new Map();
    const walk = (node) => {
        if (node === null) return 0;
        const s = node.val + walk(node.left) + walk(node.right);
        freq.set(s, (freq.get(s) || 0) + 1);
        return s;
    };
    walk(root);
    if (freq.size === 0) return [];
    let hi = 0;
    for (const c of freq.values()) if (c > hi) hi = c;
    const res = [];
    for (const [s, c] of freq.entries()) if (c === hi) res.push(s);
    return res;
};
